UPDATE PLACE
SET
  PLC_AVG_RATING = (
    SELECT COALESCE(ROUND(AVG(RVW_RATING), 1), 0.0)
    FROM REVIEW
    WHERE RVW_PLC_NO = #{plcNo}
      AND RVW_USE_YN = 'Y'
  ),
  PLC_REVIEW_CNT = (
    SELECT COUNT(*)
    FROM REVIEW
    WHERE RVW_PLC_NO = #{plcNo}
      AND RVW_USE_YN = 'Y'
  ),
  PLC_UP_DATE = NOW()
WHERE PLC_NO = #{plcNo}
